"use client";

import * as React from "react";
import { ChevronDown, ChevronUp, Play, Quote } from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { VideoPlayerPro } from "@/components/ruixen/video-player-pro";
import { cn } from "@/lib/utils";

export interface Testimonial {
  name: string;
  designation: string;
  title?: string;
  profile?: string;
  content?: string;
  mediaUrl?: string;
  thumbnail?: string;
}

export interface MultiMediaTestimonialProps {
  items: Testimonial[];
  /** Small monospace kicker rendered above the heading. */
  eyebrow?: React.ReactNode;
  heading?: React.ReactNode;
  description?: React.ReactNode;
  className?: string;
  /**
   * Collapsed wall height in px before the "show more" button appears.
   * Set to `0` to render the full wall without a collapse affordance.
   * Default `900`.
   */
  collapsedHeight?: number;
  /** Label for the expand button. Default "Show more testimonials". */
  expandLabel?: React.ReactNode;
  /** Label for the collapse button (shown when expanded). Default "Show less". */
  collapseLabel?: React.ReactNode;
}

function estimateCardHeight(t: Testimonial): number {
  let h = 110;
  if (t.title) h += 28;
  if (t.content) h += Math.max(40, Math.ceil(t.content.length / 38) * 22);
  if (t.mediaUrl) h += 520;
  else if (t.thumbnail) h += 360;
  return h;
}

function distributeToColumns<T>(
  items: T[],
  cols: number,
  weight: (item: T) => number,
): T[][] {
  const buckets: T[][] = Array.from({ length: cols }, () => []);
  const heights = new Array<number>(cols).fill(0);
  for (const item of items) {
    let minIdx = 0;
    for (let i = 1; i < cols; i++) {
      if (heights[i] < heights[minIdx]) minIdx = i;
    }
    buckets[minIdx].push(item);
    heights[minIdx] += weight(item);
  }
  return buckets;
}

function useColumnCount(): number {
  const [cols, setCols] = React.useState(1);
  React.useEffect(() => {
    const lg = window.matchMedia("(min-width: 1024px)");
    const sm = window.matchMedia("(min-width: 640px)");
    const update = () => {
      if (lg.matches) setCols(3);
      else if (sm.matches) setCols(2);
      else setCols(1);
    };
    update();
    lg.addEventListener("change", update);
    sm.addEventListener("change", update);
    return () => {
      lg.removeEventListener("change", update);
      sm.removeEventListener("change", update);
    };
  }, []);
  return cols;
}

export function MultiMediaTestimonial({
  items,
  eyebrow,
  heading,
  description,
  className,
  collapsedHeight = 900,
  expandLabel = "Show more testimonials",
  collapseLabel = "Show less",
}: MultiMediaTestimonialProps) {
  const cols = useColumnCount();
  const columns = React.useMemo(
    () => distributeToColumns(items, cols, estimateCardHeight),
    [items, cols],
  );

  const [expanded, setExpanded] = React.useState(false);
  const [naturalHeight, setNaturalHeight] = React.useState<number | null>(null);
  const contentRef = React.useRef<HTMLDivElement | null>(null);

  React.useEffect(() => {
    const el = contentRef.current;
    if (!el) return;
    const measure = () => setNaturalHeight(el.scrollHeight);
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    measure();
    return () => ro.disconnect();
  }, [columns]);

  const collapseEnabled = collapsedHeight > 0;
  const needsCollapse =
    collapseEnabled &&
    naturalHeight !== null &&
    naturalHeight > collapsedHeight;
  const showCollapseUI = needsCollapse;

  let maxHeight: string | undefined;
  if (!collapseEnabled) {
    maxHeight = undefined;
  } else if (expanded) {
    maxHeight = naturalHeight !== null ? `${naturalHeight}px` : undefined;
  } else if (naturalHeight !== null && naturalHeight <= collapsedHeight) {
    maxHeight = `${naturalHeight}px`;
  } else {
    maxHeight = `${collapsedHeight}px`;
  }

  return (
    <section className={cn("px-6 py-16", className)}>
      <div className="mx-auto max-w-7xl">
        {(eyebrow || heading || description) && (
          <div className="mb-14 text-center">
            {eyebrow && (
              <p className="mb-8 font-mono text-sm text-muted-foreground">
                {eyebrow}
              </p>
            )}
            {heading && (
              <h2 className="text-balance text-4xl font-bold leading-[1.05] tracking-tight text-foreground sm:text-5xl lg:text-6xl">
                {heading}
              </h2>
            )}
            {description && (
              <p className="mx-auto mt-6 max-w-md text-balance text-sm leading-relaxed text-muted-foreground sm:text-base">
                {description}
              </p>
            )}
          </div>
        )}

        {items.length === 0 ? (
          <p className="text-center text-muted-foreground">
            No testimonials yet.
          </p>
        ) : (
          <>
            <div className="relative">
              <div
                className="overflow-hidden transition-[max-height] duration-500 ease-out motion-reduce:transition-none"
                style={{ maxHeight }}
              >
                <div
                  ref={contentRef}
                  className="grid items-start gap-4"
                  style={{
                    gridTemplateColumns: `repeat(${cols}, minmax(0, 1fr))`,
                  }}
                >
                  {columns.map((col, ci) => (
                    <div key={ci} className="flex flex-col gap-4">
                      {col.map((item, i) => (
                        <MultiMediaTestimonialCard
                          key={`${item.name}-${ci}-${i}`}
                          testimonial={item}
                        />
                      ))}
                    </div>
                  ))}
                </div>
              </div>

              {showCollapseUI && (
                <div
                  aria-hidden
                  className={cn(
                    "pointer-events-none absolute inset-x-0 bottom-0 h-48 bg-gradient-to-t from-background via-background/80 to-transparent transition-opacity duration-500 motion-reduce:transition-none",
                    expanded ? "opacity-0" : "opacity-100",
                  )}
                />
              )}
            </div>

            {showCollapseUI && (
              <div className="mt-8 flex justify-center">
                <Button
                  type="button"
                  variant="outline"
                  size="lg"
                  onClick={() => setExpanded((v) => !v)}
                  aria-expanded={expanded}
                  className="group rounded-full px-6"
                >
                  <span>{expanded ? collapseLabel : expandLabel}</span>
                  {expanded ? (
                    <ChevronUp className="ml-1.5 h-4 w-4 transition-transform duration-300 group-hover:-translate-y-0.5" />
                  ) : (
                    <ChevronDown className="ml-1.5 h-4 w-4 transition-transform duration-300 group-hover:translate-y-0.5" />
                  )}
                </Button>
              </div>
            )}
          </>
        )}
      </div>
    </section>
  );
}

export function MultiMediaTestimonialCard({
  testimonial,
  className,
}: {
  testimonial: Testimonial;
  className?: string;
}) {
  const { name, profile, title, designation, content, mediaUrl, thumbnail } =
    testimonial;

  const [open, setOpen] = React.useState(false);

  const initial = name.charAt(0).toUpperCase();

  return (
    <article
      className={cn(
        "group flex flex-col gap-4 rounded-2xl border border-border/60 bg-card/60 p-4 shadow-sm backdrop-blur-sm transition-all duration-300 hover:border-border hover:shadow-md",
        className,
      )}
    >
      {title && (
        <h3 className="text-base font-semibold leading-snug text-foreground">
          {title}
        </h3>
      )}

      {mediaUrl ? (
        <Dialog open={open} onOpenChange={setOpen}>
          <DialogTrigger asChild>
            <button
              type="button"
              aria-label={`Play testimonial video from ${name}`}
              className="group/trigger relative block w-full overflow-hidden rounded-xl border border-border/60 bg-muted/40 outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background"
            >
              {thumbnail ? (
                /* eslint-disable-next-line @next/next/no-img-element */
                <img
                  src={thumbnail}
                  alt={name}
                  loading="lazy"
                  className="block h-auto w-full transition-transform duration-500 group-hover/trigger:scale-105"
                />
              ) : (
                <video
                  src={`${mediaUrl}#t=1`}
                  preload="metadata"
                  muted
                  playsInline
                  tabIndex={-1}
                  aria-hidden
                  className="pointer-events-none block h-auto w-full"
                />
              )}
              <div className="pointer-events-none absolute inset-0 flex items-center justify-center bg-foreground/10 transition-colors duration-300 group-hover/trigger:bg-foreground/25">
                <span className="flex h-14 w-14 items-center justify-center rounded-full bg-background/85 ring-1 ring-foreground/10 backdrop-blur-md transition-transform duration-300 group-hover/trigger:scale-110">
                  <Play className="h-6 w-6 translate-x-[1px] fill-foreground text-foreground" />
                </span>
              </div>
            </button>
          </DialogTrigger>

          {/* Mobile-dimensioned lightbox: the testimonial clips are portrait,
              so the pro player is framed at phone width and lets the video's
              intrinsic aspect ratio drive its height. */}
          <DialogContent
            className="block w-[min(88vw,360px)] max-w-[88vw] gap-0 overflow-hidden border-0 bg-transparent p-0 shadow-none"
            onOpenAutoFocus={(e) => e.preventDefault()}
          >
            <DialogTitle className="sr-only">
              Video testimonial from {name}
            </DialogTitle>
            <VideoPlayerPro src={mediaUrl} poster={thumbnail} />
          </DialogContent>
        </Dialog>
      ) : thumbnail ? (
        <div className="relative overflow-hidden rounded-xl border border-border/60">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={thumbnail}
            alt={name}
            loading="lazy"
            className="block h-auto w-full transition-transform duration-500 group-hover:scale-105"
          />
        </div>
      ) : (
        <Quote
          aria-hidden
          className="h-6 w-6 shrink-0 text-muted-foreground/40"
        />
      )}

      {content && (
        <p className="text-sm leading-relaxed text-muted-foreground">
          {content}
        </p>
      )}

      <div className="flex items-center gap-3">
        <Avatar className="h-10 w-10 ring-1 ring-foreground/10">
          {profile && <AvatarImage src={profile} alt={name} />}
          <AvatarFallback>{initial}</AvatarFallback>
        </Avatar>
        <div className="min-w-0">
          <p className="truncate text-sm font-medium text-foreground">{name}</p>
          <p className="truncate text-xs text-muted-foreground">
            {designation}
          </p>
        </div>
      </div>
    </article>
  );
}

export default MultiMediaTestimonial;

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

type ImageLoadingStatus = "loading" | "loaded" | "error";

const AvatarContext = React.createContext<{
  status: ImageLoadingStatus;
  setStatus: (status: ImageLoadingStatus) => void;
}>({ status: "loading", setStatus: () => {} });

function Avatar({ className, ...props }: React.ComponentProps<"span">) {
  const [status, setStatus] = React.useState<ImageLoadingStatus>("loading");

  return (
    <AvatarContext.Provider value={{ status, setStatus }}>
      <span
        data-slot="avatar"
        className={cn(
          "relative flex size-8 shrink-0 overflow-hidden rounded-full",
          className,
        )}
        {...props}
      />
    </AvatarContext.Provider>
  );
}

function AvatarImage({
  className,
  src,
  alt = "",
  onLoadingStatusChange,
  ...props
}: React.ComponentProps<"img"> & {
  onLoadingStatusChange?: (status: ImageLoadingStatus) => void;
}) {
  const { setStatus } = React.useContext(AvatarContext);
  const [loaded, setLoaded] = React.useState(false);

  React.useEffect(() => {
    if (!src) {
      setStatus("error");
      onLoadingStatusChange?.("error");
      return;
    }
    setLoaded(false);
    setStatus("loading");
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setLoaded(true);
      setStatus("loaded");
      onLoadingStatusChange?.("loaded");
    };
    img.onerror = () => {
      setStatus("error");
      onLoadingStatusChange?.("error");
    };
  }, [src, onLoadingStatusChange, setStatus]);

  if (!loaded) return null;

  return (
    <img
      data-slot="avatar-image"
      className={cn("aspect-square size-full object-cover", className)}
      src={src}
      alt={alt}
      {...props}
    />
  );
}

function AvatarFallback({
  className,
  delayMs,
  children,
  ...props
}: React.ComponentProps<"span"> & { delayMs?: number }) {
  const { status } = React.useContext(AvatarContext);
  const [delayElapsed, setDelayElapsed] = React.useState(!delayMs);

  React.useEffect(() => {
    if (delayMs) {
      const timer = setTimeout(() => setDelayElapsed(true), delayMs);
      return () => clearTimeout(timer);
    }
  }, [delayMs]);

  if (status === "loaded" || !delayElapsed) return null;

  return (
    <span
      data-slot="avatar-fallback"
      className={cn(
        "bg-muted flex size-full items-center justify-center rounded-full",
        className,
      )}
      {...props}
    >
      {children}
    </span>
  );
}

export { Avatar, AvatarImage, AvatarFallback };

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        outline:
          "border border-input bg-background text-foreground shadow-sm hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        rainbow:
          "group relative animate-rainbow cursor-pointer border-0 bg-[linear-gradient(#121213,#121213),linear-gradient(#121213_50%,rgba(18,18,19,0.6)_80%,rgba(18,18,19,0)),linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))] bg-[length:200%] text-primary-foreground [background-clip:padding-box,border-box,border-box] [background-origin:border-box] [border:calc(0.08*1rem)_solid_transparent] before:absolute before:bottom-[-20%] before:left-1/2 before:z-0 before:h-1/5 before:w-3/5 before:-translate-x-1/2 before:animate-rainbow before:bg-[linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))] before:[filter:blur(calc(0.8*1rem))] dark:bg-[linear-gradient(#fff,#fff),linear-gradient(#fff_50%,rgba(255,255,255,0.6)_80%,rgba(0,0,0,0)),linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))]",
        "rainbow-outline":
          "group relative animate-rainbow cursor-pointer border-0 border-input bg-[linear-gradient(#fff,#fff),linear-gradient(#fff_50%,rgba(255,255,255,0.6)_80%,rgba(0,0,0,0)),linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))] bg-[length:200%] px-4 text-foreground shadow-sm [background-clip:padding-box,border-box,border-box] [background-origin:border-box] [border:calc(0.08*1rem)_solid_transparent] before:absolute before:bottom-[-20%] before:left-1/2 before:z-0 before:h-1/5 before:w-3/5 before:-translate-x-1/2 before:animate-rainbow before:bg-[linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))] before:[filter:blur(calc(0.8*1rem))] dark:bg-[linear-gradient(#121213,#121213),linear-gradient(#121213_50%,rgba(18,18,19,0.6)_80%,rgba(18,18,19,0)),linear-gradient(90deg,var(--color-1),var(--color-5),var(--color-3),var(--color-4),var(--color-2))]",
      },
      size: {
        default: "h-9 px-4 py-2",
        sm: "h-8 rounded-xl px-3 text-xs",
        md: "h-10 rounded-xl px-4 text-sm",
        lg: "h-11 rounded-xl px-8",
        icon: "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, children, ...props }, ref) => {
    if (asChild && React.isValidElement(children)) {
      return React.cloneElement(children as React.ReactElement<any>, {
        className: cn(
          buttonVariants({ variant, size, className }),
          (children.props as any).className,
        ),
        ref,
        ...props,
      });
    }

    return (
      <button
        data-slot="button"
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      >
        {children}
      </button>
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

"use client";

import * as React from "react";
import { Dialog as DialogPrimitive } from "@base-ui/react/dialog";
import { XIcon } from "lucide-react";

import { cn } from "@/lib/utils";

function Dialog({
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Root>) {
  return <DialogPrimitive.Root data-slot="dialog" {...props} />;
}

function DialogTrigger({
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Trigger>) {
  return <DialogPrimitive.Trigger data-slot="dialog-trigger" {...props} />;
}

function DialogPortal({
  children,
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Portal>) {
  return (
    <DialogPrimitive.Portal data-slot="dialog-portal" {...props}>
      {children}
    </DialogPrimitive.Portal>
  );
}

function DialogClose({
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Close>) {
  return <DialogPrimitive.Close data-slot="dialog-close" {...props} />;
}

function DialogOverlay({
  className,
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Backdrop>) {
  return (
    <DialogPrimitive.Backdrop
      data-slot="dialog-overlay"
      className={cn(
        "data-[open]:animate-in data-[closed]:animate-out data-[closed]:fade-out-0 data-[open]:fade-in-0 fixed inset-0 z-50 bg-black/50",
        className,
      )}
      {...props}
    />
  );
}

function DialogContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Popup>) {
  return (
    <DialogPortal data-slot="dialog-portal">
      <DialogOverlay />
      <DialogPrimitive.Popup
        data-slot="dialog-content"
        className={cn(
          "bg-background data-[open]:animate-in data-[closed]:animate-out data-[closed]:fade-out-0 data-[open]:fade-in-0 data-[closed]:zoom-out-95 data-[open]:zoom-in-95 fixed top-[50%] left-[50%] z-50 grid w-full max-w-[calc(100%-2rem)] translate-x-[-50%] translate-y-[-50%] gap-4 rounded-lg border p-6 shadow-lg duration-200 sm:max-w-lg",
          className,
        )}
        {...props}
      >
        {children}
        <DialogPrimitive.Close className="ring-offset-background focus:ring-ring data-[open]:bg-accent data-[open]:text-muted-foreground absolute top-4 right-4 rounded-xs opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-hidden disabled:pointer-events-none [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4">
          <XIcon />
          <span className="sr-only">Close</span>
        </DialogPrimitive.Close>
      </DialogPrimitive.Popup>
    </DialogPortal>
  );
}

function DialogHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="dialog-header"
      className={cn("flex flex-col gap-2 text-center sm:text-left", className)}
      {...props}
    />
  );
}

function DialogFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="dialog-footer"
      className={cn(
        "flex flex-col-reverse gap-2 sm:flex-row sm:justify-end",
        className,
      )}
      {...props}
    />
  );
}

function DialogTitle({
  className,
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Title>) {
  return (
    <DialogPrimitive.Title
      data-slot="dialog-title"
      className={cn("text-lg leading-none font-semibold", className)}
      {...props}
    />
  );
}

function DialogDescription({
  className,
  ...props
}: React.ComponentProps<typeof DialogPrimitive.Description>) {
  return (
    <DialogPrimitive.Description
      data-slot="dialog-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  );
}

export {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogOverlay,
  DialogPortal,
  DialogTitle,
  DialogTrigger,
};
